import re
def norm_doc(d):
    return re.sub(r"[\s-]+", "", d.strip().casefold())
def blocking_key(rec):
    return f"{rec.get('primer_apellido','').casefold()}|{rec.get('region','').casefold()}"
def er_score(a, b):
    if norm_doc(a.get("doc","")) == norm_doc(b.get("doc","")) and blocking_key(a) == blocking_key(b):
        return 1.0
    if a.get("primer_apellido","").casefold() == b.get("primer_apellido","").casefold():
        return 0.5
    return 0.0
a = {"doc": "123", "primer_apellido": "Quispe", "region": "Lima"}
b = {"doc": "123", "primer_apellido": "Quispe", "region": "Lima"}
print(er_score(a, b))
print("criterio: 1.0 si norm_doc+blocking iguales; 0.5 solo apellido; stdlib determinista")

def rel_score(km, surname_jaccard):
    return round(0.6 * (1 if km < 2 else 0) + 0.4 * surname_jaccard, 3)
print(rel_score(1.0, 0.5), "|", rel_score(5.0, 0.5))

txs = [("A", "D", 1), ("C", "D", 1), ("A", "E", 1), ("C", "F", 1)]
def neighbors(txs, node):
    s = set()
    for x, y, _ in txs:
        if x == node:
            s.add(y)
        if y == node:
            s.add(x)
    return s
def common_counterparties(txs, a, c):
    return sorted(neighbors(txs, a) & neighbors(txs, c))
print(common_counterparties(txs, "A", "C"))

def uncertainty_band(missing, conflict):
    if conflict or len(missing) >= 2:
        return "high"
    if missing:
        return "med"
    return "low"
print(uncertainty_band([], False), "|", uncertainty_band(["a"], False), "|", uncertainty_band(["a", "b"], False))

